UPDATE `blog_article_tag` SET `deleted_at`='2026-05-10 17:46:01',`updated_at`='2026-05-10 17:46:01' WHERE `article_id` IN (632000, 632002, 632003, 632004, 632005, 632006, 632007, 632008, 632009, 632010, 632011, 632012, 632013, 632014, 632015, 632016, 632017, 632018, 632019, 632020, 632021, 632022, 632023, 632024, 632025, 632026, 632027, 632028, 632029, 632030, 632031, 632032, 632033, 632034, 632035, 632036, 632037, 632038, 632039, 632040, 632041, 632042, 632043);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-10 17:46:01',`updated_at`='2026-05-10 17:46:01' WHERE `column_id`=9600013;
UPDATE `blog_topic_article` SET `deleted_at`='2026-05-10 17:46:01',`updated_at`='2026-05-10 17:46:01' WHERE `topic_id`=9700013;

UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg INNER JOIN `blog_article` a ON a.`id` = atg.`article_id` WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`name` IN ('数据结构', '算法', '计算机基础', '编程基础');
UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE c.`id` = 9600013;
UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`id` = 9700013;
COMMIT;
